USE subastas;

START TRANSACTION;

-- Paste the exact base64 you sent between the quotes.
-- Important: your pasted value appears to contain the same PNG twice back-to-back.
-- This script automatically keeps only the first PNG if a second PNG header is found.
SET @raw_image_base64 = '';

-- Remove whitespace/newlines just in case the string was copied with line breaks.
SET @raw_image_base64 = REPLACE(REPLACE(REPLACE(REPLACE(@raw_image_base64, CHAR(13), ''), CHAR(10), ''), CHAR(9), ''), ' ', '');

-- If the pasted string accidentally contains a second PNG base64 header, keep only the first image.
SET @second_png_start = LOCATE('iVBORw0KGgo', @raw_image_base64, 2);
SET @image_base64 = IF(
    @second_png_start > 0,
    LEFT(@raw_image_base64, @second_png_start - 1),
    @raw_image_base64
);

-- Decode to binary PNG bytes.
SET @image_bytes = FROM_BASE64(@image_base64);

-- Validate that the decoded bytes start with the PNG signature: 89 50 4E 47 0D 0A 1A 0A.
-- If this returns anything other than "OK - PNG decoded", rollback and check the pasted base64.
SELECT
    CASE
        WHEN @image_bytes IS NULL THEN 'ERROR - Base64 did not decode'
        WHEN HEX(SUBSTRING(@image_bytes, 1, 8)) <> '89504E470D0A1A0A' THEN 'ERROR - decoded bytes are not a PNG'
        ELSE 'OK - PNG decoded'
    END AS image_validation,
    LENGTH(@image_bytes) AS decoded_bytes;

-- Add necessary photo rows for products that currently have no row in fotos.
-- This does NOT modify the fotos table definition; it only adds missing data.
INSERT INTO fotos (producto, foto)
SELECT p.identificador, @image_bytes
FROM productos p
WHERE NOT EXISTS (
    SELECT 1
    FROM fotos f
    WHERE f.producto = p.identificador
);

-- Replace every image currently stored in fotos.
UPDATE fotos
SET foto = @image_bytes;

-- Confirm all fotos rows now contain a PNG.
SELECT
    COUNT(*) AS total_fotos,
    SUM(CASE WHEN HEX(SUBSTRING(foto, 1, 8)) = '89504E470D0A1A0A' THEN 1 ELSE 0 END) AS fotos_con_png_valido
FROM fotos;

COMMIT;